-- ============================================================
-- QA MATRIX ENTRIES — Schema + Data (191 rows)
-- ============================================================

CREATE TABLE IF NOT EXISTS public.qa_matrix_entries (
  id                          UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  s_no                        INTEGER NOT NULL,
  source                      TEXT NOT NULL DEFAULT '',
  operation_station           TEXT NOT NULL DEFAULT '',
  designation                 TEXT NOT NULL DEFAULT '',
  concern                     TEXT NOT NULL DEFAULT '',
  defect_code                 TEXT NOT NULL DEFAULT '',
  defect_location_code        TEXT NOT NULL DEFAULT '',
  defect_rating               INTEGER NOT NULL DEFAULT 1,
  recurrence                  INTEGER NOT NULL DEFAULT 0,
  weekly_recurrence           JSONB NOT NULL DEFAULT '[]'::jsonb,
  recurrence_count_plus_defect INTEGER NOT NULL DEFAULT 0,
  trim                        JSONB NOT NULL DEFAULT '{}'::jsonb,
  chassis                     JSONB NOT NULL DEFAULT '{}'::jsonb,
  final                       JSONB NOT NULL DEFAULT '{}'::jsonb,
  q_control                   JSONB NOT NULL DEFAULT '{}'::jsonb,
  q_control_detail            JSONB NOT NULL DEFAULT '{}'::jsonb,
  control_rating              JSONB NOT NULL DEFAULT '{}'::jsonb,
  guaranteed_quality          JSONB NOT NULL DEFAULT '{}'::jsonb,
  workstation_status          TEXT NOT NULL DEFAULT 'NG',
  mfg_status                  TEXT NOT NULL DEFAULT 'NG',
  plant_status                TEXT NOT NULL DEFAULT 'NG',
  mfg_action                  TEXT NOT NULL DEFAULT '',
  resp                        TEXT NOT NULL DEFAULT '',
  target                      TEXT NOT NULL DEFAULT '',
  detection_flags             JSONB DEFAULT '{}'::jsonb,
  outside_process             JSONB DEFAULT '{}'::jsonb,
  recorded_defect             JSONB DEFAULT NULL,
  team_leader                 VARCHAR DEFAULT NULL,
  repair_time                 VARCHAR DEFAULT NULL,
  implementation_date         VARCHAR DEFAULT NULL,
  audit_date_name             VARCHAR DEFAULT NULL,
  dvm_pqg                     CHAR DEFAULT NULL,
  dvr_dvt                     CHAR DEFAULT NULL,
  product_audit_sca           CHAR DEFAULT NULL,
  warranty                    VARCHAR DEFAULT NULL,
  reoccurrence_flag           VARCHAR DEFAULT NULL,
  created_at                  TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at                  TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Indexes
CREATE INDEX IF NOT EXISTS idx_qa_matrix_s_no ON public.qa_matrix_entries (s_no);
CREATE INDEX IF NOT EXISTS idx_qa_matrix_defect_code ON public.qa_matrix_entries (defect_code);
CREATE INDEX IF NOT EXISTS idx_qa_matrix_location_code ON public.qa_matrix_entries (defect_location_code);

-- RLS
ALTER TABLE public.qa_matrix_entries ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Allow public read" ON public.qa_matrix_entries FOR SELECT USING (true);
CREATE POLICY "Allow public insert" ON public.qa_matrix_entries FOR INSERT WITH CHECK (true);
CREATE POLICY "Allow public update" ON public.qa_matrix_entries FOR UPDATE USING (true);
CREATE POLICY "Allow public delete" ON public.qa_matrix_entries FOR DELETE USING (true);

